# Formatting for JS/TS
def format_cat(cat_id, title, desc, icon, color, diff, qs):
    out = f"  {{\n    id: \"{cat_id}\",\n    title: \"{title}\",\n    description: \"{desc}\",\n    icon: \"{icon}\",\n    colorClass: \"{color}\",\n    difficulty: \"{diff}\",\n    questions: [\n"
    for q in qs:
        # Escape quotes in explanation
        expl = q['explanation'].replace('"', '\\"')
        out += f"      {{ question: \"{q['question']}\", options: {q['options']}, correctAnswer: {q['correctAnswer']}, explanation: \"{expl}\" }},\n"
    out += "    ],\n  },"
    return out

